import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getProduct, addReview } from '../services/api';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const ProductDetail = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [qty, setQty] = useState(1);
  const [activeImg, setActiveImg] = useState(0);
  const [review, setReview] = useState({ rating: 5, comment: '' });
  const { addItem } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    getProduct(id)
      .then(r => setProduct(r.data))
      .catch(() => navigate('/products'));
  }, [id, navigate]);

  const handleAddCart = () => { 
    addItem(product, qty); 
    toast.success('Added to cart!'); 
  };

  const handleBuyNow = () => { 
    addItem(product, qty); 
    navigate('/cart'); 
  };

  const handleReview = async (e) => {
    e.preventDefault();
    if (!user) return navigate('/login');
    try {
      await addReview(id, review);
      toast.success('Review submitted!');
      const r = await getProduct(id);
      setProduct(r.data);
    } catch (err) { 
      toast.error(err.response?.data?.message || 'Error'); 
    }
  };

  if (!product) return <div className="loader">Loading...</div>;

  // FIXED: Corrected the optional chaining syntax
  const img = product.images && product.images[activeImg] 
    ? product.images[activeImg].url 
    : `https://via.placeholder.com/500?text=${product.name}`;

  const price = product.discountPrice > 0 ? product.discountPrice : product.price;

  return (
    <div className="product-detail">
      <div className="detail-gallery">
        <div className="main-img-container">
          <img className="detail-main-img" src={img} alt={product.name} />
        </div>
        {product.images?.length > 1 && (
          <div className="thumbnail-row">
            {product.images.map((im, i) => (
              <img 
                key={i} 
                src={im.url} 
                alt={`${product.name} ${i}`} 
                className={i === activeImg ? 'active' : ''} 
                onClick={() => setActiveImg(i)} 
              />
            ))}
          </div>
        )}
      </div>

      <div className="detail-info">
        <p className="detail-category">{product.category} / {product.brand}</p>
        <h1>{product.name}</h1>
        <div className="detail-rating">
          {'★'.repeat(Math.round(product.rating))}{'☆'.repeat(5 - Math.round(product.rating))}
          <span> ({product.numReviews} reviews)</span>
        </div>
        <div className="detail-price">
          <span className="price-big">PKR {price.toLocaleString()}</span>
          {product.discountPrice > 0 && <span className="price-striked">PKR {product.price.toLocaleString()}</span>}
        </div>
        <p className="detail-desc">{product.description}</p>

        {product.specifications?.length > 0 && (
          <table className="specs-table">
            <tbody>
              {product.specifications.map((s, i) => (
                <tr key={i}><td>{s.key}</td><td>{s.value}</td></tr>
              ))}
            </tbody>
          </table>
        )}

        <div className="detail-actions">
          <div className="qty-control">
            <button onClick={() => setQty(q => Math.max(1, q - 1))}>-</button>
            <span>{qty}</span>
            <button onClick={() => setQty(q => Math.min(product.stock, q + 1))}>+</button>
          </div>
          <button className="btn-primary" onClick={handleAddCart} disabled={product.stock === 0}>
            Add to Cart
          </button>
          <button className="btn-secondary" onClick={handleBuyNow} disabled={product.stock === 0}>
            Buy Now
          </button>
        </div>
        <p className="stock-info">{product.stock > 0 ? `✅ ${product.stock} in stock` : '❌ Out of stock'}</p>
        {product.seller && <p className="seller-info">Sold by: {product.seller.name}</p>}
      </div>

      <div className="reviews-section">
        <h2>Customer Reviews</h2>
        {product.reviews?.length > 0 ? (
          product.reviews.map(r => (
            <div key={r._id} className="review-card">
              <div className="review-header">
                <strong>{r.name}</strong>
                <span>{'★'.repeat(r.rating)}</span>
              </div>
              <p>{r.comment}</p>
              <small>{new Date(r.createdAt).toLocaleDateString()}</small>
            </div>
          ))
        ) : (
          <p>No reviews yet. Be the first to review!</p>
        )}

        {user && (
          <form className="review-form" onSubmit={handleReview}>
            <h3>Write a Review</h3>
            <select value={review.rating} onChange={e => setReview(prev => ({ ...prev, rating: Number(e.target.value) }))}>
              {[5,4,3,2,1].map(n => <option key={n} value={n}>{n} Stars</option>)}
            </select>
            <textarea 
              placeholder="Share your experience..." 
              value={review.comment} 
              onChange={e => setReview(prev => ({ ...prev, comment: e.target.value }))} 
              required 
            />
            <button className="btn-primary" type="submit">Submit Review</button>
          </form>
        )}
      </div>
    </div>
  );
};

export default ProductDetail;
